const table = msg.req.params.table;
const id = msg.req.params.id;
const method = msg.req.method;
const p = msg.payload;

// ไม่ต้องส่ง SET NAMES แล้วเพราะตั้งใน Config แล้ว
let sql = "";

if (method === 'GET') {
    if (id && id !== '0') sql = `SELECT * FROM ${table} WHERE id = ${id}`;
    else sql = `SELECT * FROM ${table}`;
} else if (method === 'POST') {
    const keys = Object.keys(p).join(',');
    const values = Object.values(p).map(v => `'${v}'`).join(',');
    sql = `INSERT INTO ${table} (${keys}) VALUES (${values})`;
} else if (method === 'PUT') {
    const updates = Object.entries(p).map(([k, v]) => {
        if (k === 'id') return null;
        return `${k}='${v}'`;
    }).filter(x => x).join(',');
    sql = `UPDATE ${table} SET ${updates} WHERE id = ${id}`;
} else if (method === 'DELETE') {
    sql = `DELETE FROM ${table} WHERE id = ${id}`;
}

msg.topic = sql;
return msg;

msg.headers = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Content-Type': 'application/json; charset=utf-8'
};
return msg;
